// ---- Entity ----
import androidx.room.ColumnInfo
import androidx.room.Entity
import androidx.room.PrimaryKey

@Entity(tableName = "players")
data class PlayerEntity(
    @PrimaryKey(autoGenerate = true)
    val id: Int = 0,

    @ColumnInfo(name = "player_name")
    val name: String,

    @ColumnInfo(name = "health")
    val health: Int,

    @ColumnInfo(name = "attack")
    val attack: Int,

    @ColumnInfo(name = "level")
    val level: Int,

    @ColumnInfo(name = "is_active")
    val isActive: Boolean = true
)

// ---- DAO (Data Access Object) ----
import androidx.room.Dao
import androidx.room.Delete
import androidx.room.Insert
import androidx.room.Query
import androidx.room.Update
import kotlinx.coroutines.flow.Flow

@Dao
interface PlayerDao {
    // ---- Insert ----
    @Insert
    suspend fun insertPlayer(player: PlayerEntity): Long

    @Insert
    suspend fun insertPlayers(players: List<PlayerEntity>): List<Long>

    // ---- Query ----
    @Query("SELECT * FROM players ORDER BY id DESC")
    fun getAllPlayers(): Flow<List<PlayerEntity>>

    @Query("SELECT * FROM players WHERE id = :id")
    suspend fun getPlayerById(id: Int): PlayerEntity?

    @Query("SELECT * FROM players WHERE is_active = 1")
    fun getActivePlayers(): Flow<List<PlayerEntity>>

    @Query("SELECT * FROM players WHERE level >= :minLevel")
    fun getPlayersByLevel(minLevel: Int): Flow<List<PlayerEntity>>

    @Query("SELECT COUNT(*) FROM players")
    suspend fun getPlayerCount(): Int

    // ---- Update ----
    @Update
    suspend fun updatePlayer(player: PlayerEntity)

    @Query("UPDATE players SET health = :health WHERE id = :id")
    suspend fun updateHealth(id: Int, health: Int)

    @Query("UPDATE players SET level = level + 1 WHERE id = :id")
    suspend fun levelUp(id: Int)

    // ---- Delete ----
    @Delete
    suspend fun deletePlayer(player: PlayerEntity)

    @Query("DELETE FROM players WHERE id = :id")
    suspend fun deletePlayerById(id: Int)

    @Query("DELETE FROM players WHERE is_active = 0")
    suspend fun deleteInactivePlayers()

    @Query("DELETE FROM players")
    suspend fun deleteAll()
}

// ---- Database ----
import androidx.room.Database
import androidx.room.Room
import androidx.room.RoomDatabase
import android.content.Context

@Database(
    entities = [PlayerEntity::class],
    version = 1,
    exportSchema = false
)
abstract class AppDatabase : RoomDatabase() {
    abstract fun playerDao(): PlayerDao

    companion object {
        @Volatile
        private var INSTANCE: AppDatabase? = null

        fun getInstance(context: Context): AppDatabase {
            return INSTANCE ?: synchronized(this) {
                val instance = Room.databaseBuilder(
                    context.applicationContext,
                    AppDatabase::class.java,
                    "game_database"
                )
                    .fallbackToDestructiveMigration()
                    .build()
                INSTANCE = instance
                instance
            }
        }
    }
}

// ---- Repository ----
class PlayerRepository(private val dao: PlayerDao) {
    fun getAllPlayers(): Flow<List<PlayerEntity>> = dao.getAllPlayers()

    fun getActivePlayers(): Flow<List<PlayerEntity>> = dao.getActivePlayers()

    fun getPlayersByLevel(minLevel: Int): Flow<List<PlayerEntity>> = dao.getPlayersByLevel(minLevel)

    suspend fun insertPlayer(name: String, health: Int, attack: Int, level: Int): Long {
        val player = PlayerEntity(
            name = name,
            health = health,
            attack = attack,
            level = level
        )
        return dao.insertPlayer(player)
    }

    suspend fun updatePlayer(player: PlayerEntity) = dao.updatePlayer(player)

    suspend fun updateHealth(id: Int, health: Int) = dao.updateHealth(id, health)

    suspend fun levelUp(id: Int) = dao.levelUp(id)

    suspend fun deletePlayer(player: PlayerEntity) = dao.deletePlayer(player)

    suspend fun deletePlayerById(id: Int) = dao.deletePlayerById(id)

    suspend fun deleteInactivePlayers() = dao.deleteInactivePlayers()

    suspend fun deleteAll() = dao.deleteAll()

    suspend fun getPlayerById(id: Int): PlayerEntity? = dao.getPlayerById(id)

    suspend fun getPlayerCount(): Int = dao.getPlayerCount()
}

// ---- ViewModel ----
class RoomViewModel(private val repository: PlayerRepository) : ViewModel() {
    val allPlayers: StateFlow<List<PlayerEntity>> = repository.getAllPlayers()
        .stateIn(
            scope = viewModelScope,
            started = SharingStarted.WhileSubscribed(),
            initialValue = emptyList()
        )

    private val _selectedPlayer = MutableStateFlow<PlayerEntity?>(null)
    val selectedPlayer: StateFlow<PlayerEntity?> = _selectedPlayer.asStateFlow()

    private val _isLoading = MutableStateFlow(false)
    val isLoading: StateFlow<Boolean> = _isLoading.asStateFlow()

    private val _error = MutableStateFlow<String?>(null)
    val error: StateFlow<String?> = _error.asStateFlow()

    fun addPlayer(name: String, health: Int, attack: Int, level: Int) {
        viewModelScope.launch {
            _isLoading.value = true
            try {
                repository.insertPlayer(name, health, attack, level)
                _error.value = null
            } catch (e: Exception) {
                _error.value = "Failed to add player: ${e.message}"
            } finally {
                _isLoading.value = false
            }
        }
    }

    fun updateHealth(id: Int, health: Int) {
        viewModelScope.launch {
            try {
                repository.updateHealth(id, health)
            } catch (e: Exception) {
                _error.value = "Failed to update health: ${e.message}"
            }
        }
    }

    fun levelUp(id: Int) {
        viewModelScope.launch {
            try {
                repository.levelUp(id)
            } catch (e: Exception) {
                _error.value = "Failed to level up: ${e.message}"
            }
        }
    }

    fun deletePlayer(player: PlayerEntity) {
        viewModelScope.launch {
            try {
                repository.deletePlayer(player)
                if (_selectedPlayer.value?.id == player.id) {
                    _selectedPlayer.value = null
                }
            } catch (e: Exception) {
                _error.value = "Failed to delete player: ${e.message}"
            }
        }
    }

    fun selectPlayer(player: PlayerEntity) {
        _selectedPlayer.value = player
    }

    fun clearError() {
        _error.value = null
    }

    fun deleteAll() {
        viewModelScope.launch {
            try {
                repository.deleteAll()
                _selectedPlayer.value = null
            } catch (e: Exception) {
                _error.value = "Failed to delete all: ${e.message}"
            }
        }
    }
}

// ---- Factory for ViewModel ----
class RoomViewModelFactory(private val repository: PlayerRepository) : ViewModelProvider.Factory {
    override fun <T : ViewModel> create(modelClass: Class<T>): T {
        if (modelClass.isAssignableFrom(RoomViewModel::class.java)) {
            @Suppress("UNCHECKED_CAST")
            return RoomViewModel(repository) as T
        }
        throw IllegalArgumentException("Unknown ViewModel class")
    }
}

